package graphql

// Federation resolvers (B14.6b). The hub fans out a small set of read-only
// queries to every active spoke via the B14.6a fan-out client, decorates
// each row with routing metadata (node_id, project_id, project_url,
// write_capability, status), and merges the per-spoke responses into a
// single result. Local query types (beads, runs, projects) are unchanged —
// these federated queries ship in parallel so existing local views keep
// working.

import (
	"context"
	"encoding/json"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// FederationProvider exposes the hub-side state required by the federated
// query resolvers. The Resolver is wired with a nil provider on non-hub
// servers; resolvers degrade to empty-list responses in that case.
type FederationProvider interface {
	// Spokes returns a snapshot of registered spokes. Implementations should
	// return a copy that callers may sort or filter without affecting the
	// underlying registry.
	Spokes() []federation.SpokeRecord
	// FanOut executes the supplied request against every spoke returned by
	// Spokes (the implementation may apply its own active/stale policy) and
	// returns the merged FanOutResult.
	FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error)
}

// federationCapWrite is the capability string a spoke advertises when it
// allows writes from federated callers. Read-only fan-out is the v1 default
// so this field is always false until a spoke explicitly opts in.
const federationCapWrite = "write"

// federationIdentityPrefix mirrors the synthetic capability used by the hub
// to stash the identity fingerprint on a SpokeRecord. Filtered out of the
// FederationNode.capabilities surface so clients never see it.
const federationIdentityPrefix = "@identity:"

// FederationNodes returns one row per registered spoke decorated with the
// most recent fan-out outcome. When the server is not in hub mode (Resolver
// has no FederationProvider) the result is an empty list.
func (r *queryResolver) FederationNodes(ctx context.Context) ([]*FederationNode, error) {
	if r.Federation == nil {
		return []*FederationNode{}, nil
	}
	spokes := r.Federation.Spokes()
	out := make([]*FederationNode, 0, len(spokes))
	for _, s := range spokes {
		out = append(out, federationNodeFromSpoke(s, ""))
	}
	return out, nil
}

// FederatedBeads fans out a beads query and merges the resulting edges into
// FederatedBead rows.
func (r *queryResolver) FederatedBeads(ctx context.Context, status *string, label *string, projectID *string) ([]*FederatedBead, error) {
	if r.Federation == nil {
		return []*FederatedBead{}, nil
	}
	const beadsQuery = `query FedBeads($status:String,$label:String,$projectID:String){
  beads(first:200,status:$status,label:$label,projectID:$projectID){
    edges{node{id title status priority issueType owner createdAt createdBy updatedAt labels projectID parent description acceptance notes}}
  }
}`
	vars := map[string]any{}
	if status != nil {
		vars["status"] = *status
	}
	if label != nil {
		vars["label"] = *label
	}
	if projectID != nil {
		vars["projectID"] = *projectID
	}
	res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: beadsQuery, Variables: vars})
	if err != nil {
		return nil, err
	}
	spokeIndex := indexSpokes(r.Federation.Spokes())
	out := []*FederatedBead{}
	for _, n := range res.Nodes {
		if n.Outcome != federation.OutcomeOK {
			continue
		}
		var resp struct {
			Data struct {
				Beads struct {
					Edges []struct {
						Node *Bead `json:"node"`
					} `json:"edges"`
				} `json:"beads"`
			} `json:"data"`
		}
		if err := json.Unmarshal(n.Response, &resp); err != nil {
			continue
		}
		s := spokeIndex[n.NodeID]
		writeCap := hasCapability(s.Capabilities, federationCapWrite)
		statusStr := string(s.Status)
		for _, e := range resp.Data.Beads.Edges {
			if e.Node == nil {
				continue
			}
			out = append(out, &FederatedBead{
				NodeID:          n.NodeID,
				ProjectID:       e.Node.ProjectID,
				ProjectURL:      n.URL,
				WriteCapability: writeCap,
				Status:          statusStr,
				Bead:            e.Node,
			})
		}
	}
	return out, nil
}

// FederatedRuns fans out a runs query and merges the resulting edges into
// FederatedRun rows.
func (r *queryResolver) FederatedRuns(ctx context.Context, layer *RunLayer, projectID *string) ([]*FederatedRun, error) {
	if r.Federation == nil {
		return []*FederatedRun{}, nil
	}
	const runsQuery = `query FedRuns($layer:RunLayer,$projectID:String){
  runs(first:200,layer:$layer,projectID:$projectID){
    edges{node{id layer status projectID startedAt completedAt beadId artifactId parentRunId childRunIds}}
  }
}`
	vars := map[string]any{}
	if layer != nil {
		vars["layer"] = string(*layer)
	}
	if projectID != nil {
		vars["projectID"] = *projectID
	}
	res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: runsQuery, Variables: vars})
	if err != nil {
		return nil, err
	}
	spokeIndex := indexSpokes(r.Federation.Spokes())
	out := []*FederatedRun{}
	for _, n := range res.Nodes {
		if n.Outcome != federation.OutcomeOK {
			continue
		}
		var resp struct {
			Data struct {
				Runs struct {
					Edges []struct {
						Node *Run `json:"node"`
					} `json:"edges"`
				} `json:"runs"`
			} `json:"data"`
		}
		if err := json.Unmarshal(n.Response, &resp); err != nil {
			continue
		}
		s := spokeIndex[n.NodeID]
		writeCap := hasCapability(s.Capabilities, federationCapWrite)
		statusStr := string(s.Status)
		for _, e := range resp.Data.Runs.Edges {
			if e.Node == nil {
				continue
			}
			out = append(out, &FederatedRun{
				NodeID:          n.NodeID,
				ProjectID:       e.Node.ProjectID,
				ProjectURL:      n.URL,
				WriteCapability: writeCap,
				Status:          statusStr,
				Run:             e.Node,
			})
		}
	}
	return out, nil
}

// FederatedProjects fans out a projects query and merges the resulting edges
// into FederatedProject rows.
func (r *queryResolver) FederatedProjects(ctx context.Context, includeUnreachable *bool) ([]*FederatedProject, error) {
	if r.Federation == nil {
		return []*FederatedProject{}, nil
	}
	const projectsQuery = `query FedProjects($inc:Boolean){
  projects(first:200,includeUnreachable:$inc){
    edges{node{id name path gitRemote registeredAt lastSeen unreachable tombstonedAt}}
  }
}`
	vars := map[string]any{}
	if includeUnreachable != nil {
		vars["inc"] = *includeUnreachable
	}
	res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: projectsQuery, Variables: vars})
	if err != nil {
		return nil, err
	}
	spokeIndex := indexSpokes(r.Federation.Spokes())
	out := []*FederatedProject{}
	for _, n := range res.Nodes {
		if n.Outcome != federation.OutcomeOK {
			continue
		}
		var resp struct {
			Data struct {
				Projects struct {
					Edges []struct {
						Node *Project `json:"node"`
					} `json:"edges"`
				} `json:"projects"`
			} `json:"data"`
		}
		if err := json.Unmarshal(n.Response, &resp); err != nil {
			continue
		}
		s := spokeIndex[n.NodeID]
		writeCap := hasCapability(s.Capabilities, federationCapWrite)
		statusStr := string(s.Status)
		for _, e := range resp.Data.Projects.Edges {
			if e.Node == nil {
				continue
			}
			out = append(out, &FederatedProject{
				NodeID:          n.NodeID,
				ProjectID:       e.Node.ID,
				ProjectURL:      n.URL,
				WriteCapability: writeCap,
				Status:          statusStr,
				Project:         e.Node,
			})
		}
	}
	return out, nil
}

// federationNodeFromSpoke materializes one FederationNode row, filtering the
// synthetic identity capability and stamping a lastError diagnostic when
// supplied (e.g. for a version-skew handshake).
func federationNodeFromSpoke(s federation.SpokeRecord, lastError string) *FederationNode {
	caps := make([]string, 0, len(s.Capabilities))
	for _, c := range s.Capabilities {
		if strings.HasPrefix(c, federationIdentityPrefix) {
			continue
		}
		caps = append(caps, c)
	}
	n := &FederationNode{
		ID:              s.NodeID,
		NodeID:          s.NodeID,
		Name:            s.Name,
		URL:             s.URL,
		Status:          string(s.Status),
		DdxVersion:      s.DDxVersion,
		SchemaVersion:   s.SchemaVersion,
		Capabilities:    caps,
		RegisteredAt:    s.RegisteredAt.UTC().Format(time.RFC3339),
		WriteCapability: hasCapability(caps, federationCapWrite),
	}
	if !s.LastHeartbeat.IsZero() {
		ts := s.LastHeartbeat.UTC().Format(time.RFC3339)
		n.LastHeartbeat = &ts
	}
	if lastError != "" {
		le := lastError
		n.LastError = &le
	}
	return n
}

func hasCapability(caps []string, want string) bool {
	for _, c := range caps {
		if c == want {
			return true
		}
	}
	return false
}

func indexSpokes(spokes []federation.SpokeRecord) map[string]federation.SpokeRecord {
	out := make(map[string]federation.SpokeRecord, len(spokes))
	for _, s := range spokes {
		out[s.NodeID] = s
	}
	return out
}

package graphql_test

// Federation resolver integration tests (B14.6b). Exercises the four federated
// queries (federationNodes, federatedBeads, federatedRuns, federatedProjects)
// against two mock spoke servers. Verifies row shape, routing metadata, the
// partial-result rendering when one spoke is offline, and the version-skew
// rendering when one spoke is filtered by the handshake.

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/DocumentDrivenDX/ddx/internal/federation"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
)

// stubFederation is a minimal FederationProvider backed by a fixed list of
// spokes and a real (in-process) FanOutClient pointed at httptest spoke
// servers.
type stubFederation struct {
	spokes []federation.SpokeRecord
	client *federation.FanOutClient
}

func (s *stubFederation) Spokes() []federation.SpokeRecord {
	out := make([]federation.SpokeRecord, len(s.spokes))
	copy(out, s.spokes)
	return out
}

func (s *stubFederation) FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error) {
	return s.client.Execute(ctx, s.spokes, req)
}

// newSpokeServer spins up an httptest server whose /graphql endpoint returns
// the canned JSON payload supplied by handler.
func newSpokeServer(t *testing.T, handlerFn func(req map[string]any) any) *httptest.Server {
	t.Helper()
	mux := http.NewServeMux()
	mux.HandleFunc("/graphql", func(w http.ResponseWriter, r *http.Request) {
		var body map[string]any
		_ = json.NewDecoder(r.Body).Decode(&body)
		w.Header().Set("Content-Type", "application/json")
		_ = json.NewEncoder(w).Encode(handlerFn(body))
	})
	srv := httptest.NewServer(mux)
	t.Cleanup(srv.Close)
	return srv
}

// newGQLHandlerWithFederation wires a minimal Resolver pointed at the supplied
// FederationProvider. The local query state provider is the same stub the
// other integration tests use, but no local data is exercised here.
func newGQLHandlerWithFederation(t *testing.T, fed ddxgraphql.FederationProvider) http.Handler {
	t.Helper()
	workDir, store := setupIntegrationDir(t)
	state := newTestStateProvider(workDir, store)
	gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers: &ddxgraphql.Resolver{
			State:      state,
			WorkingDir: workDir,
			Actions:    testActionDispatcher{},
			Federation: fed,
		},
		Directives: ddxgraphql.DirectiveRoot{},
	}))
	gqlSrv.AddTransport(transport.POST{})
	return gqlSrv
}

// TestFederation_QueryShape_TwoHealthySpokes exercises all four federated
// queries against two mock spokes, both healthy, and verifies that each
// returned row carries the routing metadata (nodeId, projectId, projectUrl,
// writeCapability, status) along with the typed payload shape.
func TestFederation_QueryShape_TwoHealthySpokes(t *testing.T) {
	skipIntegrationInShort(t)
	now := time.Date(2026, 5, 2, 12, 0, 0, 0, time.UTC)

	spoke1 := newSpokeServer(t, func(req map[string]any) any {
		// Same canned response for any query — body is asserted by the
		// resolver decode path, not by query string.
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-A1", "title": "spoke1 bead", "status": "open",
						"priority": 0, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p1",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-1", "layer": "run", "status": "success",
						"projectID": "p1", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p1", "name": "spoke1-proj", "path": "/tmp/p1",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})
	spoke2 := newSpokeServer(t, func(req map[string]any) any {
		return map[string]any{
			"data": map[string]any{
				"beads": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "ddx-B1", "title": "spoke2 bead", "status": "open",
						"priority": 1, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
						"projectID": "p2",
					}},
				}},
				"runs": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "run-2", "layer": "run", "status": "running",
						"projectID": "p2", "childRunIds": []string{},
					}},
				}},
				"projects": map[string]any{"edges": []map[string]any{
					{"node": map[string]any{
						"id": "p2", "name": "spoke2-proj", "path": "/tmp/p2",
						"registeredAt": "2026-04-30T00:00:00Z",
						"lastSeen":     "2026-05-02T00:00:00Z",
					}},
				}},
			},
		}
	})

	fed := &stubFederation{
		client: federation.NewFanOutClient(),
		spokes: []federation.SpokeRecord{
			{
				NodeID: "node-spoke1", Name: "spoke1", URL: spoke1.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "@identity:abc"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
			{
				NodeID: "node-spoke2", Name: "spoke2", URL: spoke2.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				Capabilities: []string{"read", "write"},
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
		},
	}
	fed.client.HubDDxVersion = "0.1.0"
	fed.client.HubSchemaVersion = federation.CurrentSchemaVersion
	fed.client.PerNodeTimeout = 2 * time.Second

	h := newGQLHandlerWithFederation(t, fed)

	// federationNodes: surface should match spoke registry; @identity:* is
	// stripped; writeCapability flips per-spoke; lastHeartbeat is non-null
	// because the registry has a heartbeat timestamp.
	respNodes := gqlPost(t, h, `{ federationNodes {
		id nodeId name url status ddxVersion schemaVersion
		capabilities registeredAt lastHeartbeat writeCapability lastError
	} }`)
	var nodesData struct {
		FederationNodes []struct {
			ID              string   `json:"id"`
			NodeID          string   `json:"nodeId"`
			Name            string   `json:"name"`
			URL             string   `json:"url"`
			Status          string   `json:"status"`
			DdxVersion      string   `json:"ddxVersion"`
			SchemaVersion   string   `json:"schemaVersion"`
			Capabilities    []string `json:"capabilities"`
			RegisteredAt    string   `json:"registeredAt"`
			LastHeartbeat   *string  `json:"lastHeartbeat"`
			WriteCapability bool     `json:"writeCapability"`
			LastError       *string  `json:"lastError"`
		} `json:"federationNodes"`
	}
	if err := json.Unmarshal(respNodes["data"], &nodesData); err != nil {
		t.Fatalf("unmarshal nodes: %v", err)
	}
	if len(nodesData.FederationNodes) != 2 {
		t.Fatalf("want 2 federation nodes, got %d", len(nodesData.FederationNodes))
	}
	for _, n := range nodesData.FederationNodes {
		for _, c := range n.Capabilities {
			if len(c) > 0 && c[0] == '@' {
				t.Errorf("synthetic capability %q leaked through, expected filtered", c)
			}
		}
		if n.LastHeartbeat == nil {
			t.Errorf("node %s: expected non-null lastHeartbeat", n.NodeID)
		}
	}
	if got := nodesData.FederationNodes[0].WriteCapability; got != false {
		t.Errorf("spoke1 writeCapability: want false, got %v", got)
	}
	if got := nodesData.FederationNodes[1].WriteCapability; got != true {
		t.Errorf("spoke2 writeCapability: want true, got %v", got)
	}

	// federatedBeads: one row per spoke; each row carries projectUrl ==
	// spoke URL and the bead nested payload.
	respBeads := gqlPost(t, h, `{ federatedBeads {
		nodeId projectId projectUrl writeCapability status bead { id title status projectID }
	} }`)
	var beadsData struct {
		FederatedBeads []struct {
			NodeID          string  `json:"nodeId"`
			ProjectID       *string `json:"projectId"`
			ProjectURL      string  `json:"projectUrl"`
			WriteCapability bool    `json:"writeCapability"`
			Status          string  `json:"status"`
			Bead            struct {
				ID        string  `json:"id"`
				Title     string  `json:"title"`
				Status    string  `json:"status"`
				ProjectID *string `json:"projectID"`
			} `json:"bead"`
		} `json:"federatedBeads"`
	}
	if err := json.Unmarshal(respBeads["data"], &beadsData); err != nil {
		t.Fatalf("unmarshal beads: %v", err)
	}
	if len(beadsData.FederatedBeads) != 2 {
		t.Fatalf("want 2 federated beads, got %d", len(beadsData.FederatedBeads))
	}
	seenURL := map[string]bool{spoke1.URL: false, spoke2.URL: false}
	for _, fb := range beadsData.FederatedBeads {
		if _, ok := seenURL[fb.ProjectURL]; !ok {
			t.Errorf("unexpected projectUrl %q", fb.ProjectURL)
		}
		seenURL[fb.ProjectURL] = true
		if fb.ProjectID == nil || *fb.ProjectID == "" {
			t.Errorf("row %s: expected non-empty projectId", fb.NodeID)
		}
		if fb.Bead.ID == "" {
			t.Errorf("row %s: expected non-empty bead.id", fb.NodeID)
		}
	}
	for url, hit := range seenURL {
		if !hit {
			t.Errorf("expected a federated row for spoke URL %s", url)
		}
	}

	// federatedRuns: one row per spoke; layer/status round-trip.
	respRuns := gqlPost(t, h, `{ federatedRuns {
		nodeId projectId projectUrl writeCapability status run { id layer status }
	} }`)
	var runsData struct {

package federation

import (
	"bytes"
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

// DefaultFanOutMaxConcurrency caps the number of in-flight per-spoke requests.
const DefaultFanOutMaxConcurrency = 8

// DefaultFanOutPerNodeTimeout is the default per-node deadline for one fan-out call.
const DefaultFanOutPerNodeTimeout = 5 * time.Second

// SkipReason is a short, machine-readable code describing why a spoke was
// skipped before any HTTP call was issued.
type SkipReason string

const (
	// SkipReasonIncompatibleVersion indicates the version handshake against the
	// hub's own version+schema rejected this spoke (e.g. major mismatch,
	// schema mismatch, unparseable ddx_version, …). The Handshake reason is
	// included in the logged message.
	SkipReasonIncompatibleVersion SkipReason = "incompatible_version"
	// SkipReasonMissingCapability indicates the spoke does not advertise one of
	// the capabilities required for this query.
	SkipReasonMissingCapability SkipReason = "missing_capability"
	// SkipReasonInvalidURL indicates the spoke's persisted URL did not parse.
	SkipReasonInvalidURL SkipReason = "invalid_url"
)

// NodeOutcomeKind describes how a single spoke contributed (or did not
// contribute) to a fan-out call. The hub uses this to update per-spoke status
// distinctly: offline (immediate transport failure on this fan-out) vs stale
// (heartbeat-overdue badge from the registry) vs ok.
type NodeOutcomeKind string

const (
	// OutcomeOK means the spoke returned a response (any HTTP 2xx).
	OutcomeOK NodeOutcomeKind = "ok"
	// OutcomeOffline means the transport itself failed: connection refused,
	// DNS error, TLS handshake failed, mid-response disconnect, etc. The hub
	// flips the spoke's registry status to StatusOffline on this outcome.
	OutcomeOffline NodeOutcomeKind = "offline"
	// OutcomeTimeout means the per-node timeout fired before a response was
	// fully received. Distinct from offline so callers can keep the spoke's
	// last-known status (likely stale) rather than promote it to offline.
	OutcomeTimeout NodeOutcomeKind = "timeout"
	// OutcomeHTTPError means the spoke responded with a non-2xx status. The
	// transport worked, so we do not flip to offline; the body is captured.
	OutcomeHTTPError NodeOutcomeKind = "http_error"
	// OutcomeSkipped means the spoke was filtered out before fan-out; see
	// NodeResult.SkipReason.
	OutcomeSkipped NodeOutcomeKind = "skipped"
)

// FanOutRequest is the GraphQL payload to send to every active spoke.
type FanOutRequest struct {
	Query         string         `json:"query"`
	OperationName string         `json:"operationName,omitempty"`
	Variables     map[string]any `json:"variables,omitempty"`
	// RequiredCapabilities, if non-empty, filters out spokes that do not
	// advertise every named capability in their SpokeRecord.Capabilities.
	RequiredCapabilities []string `json:"-"`
}

// NodeResult is a single spoke's contribution to a fan-out call.
type NodeResult struct {
	NodeID string
	URL    string
	// Status, when non-empty, is the registry status the hub should record for
	// this spoke as a result of this fan-out (StatusOffline on transport
	// failure). Empty means "do not change registry status".
	Status SpokeStatus
	// Outcome classifies how this spoke contributed.
	Outcome NodeOutcomeKind
	// Response is the raw GraphQL response body for OutcomeOK. The hub merges
	// it into the federated response shape. Empty otherwise.
	Response json.RawMessage
	// HTTPStatus is the HTTP status code seen, or 0 on transport failure.
	HTTPStatus int
	// Err is the underlying error for non-OK outcomes.
	Err error
	// SkipReason is set when Outcome == OutcomeSkipped.
	SkipReason SkipReason
	// SkipDetail is a free-form human message accompanying SkipReason.
	SkipDetail string
	// Duration is the wall time spent on this spoke's call.
	Duration time.Duration
}

// FanOutResult is the merged outcome of a fan-out call.
type FanOutResult struct {
	// Responses holds one entry per spoke that returned 2xx, keyed by node_id.
	// The value is the raw GraphQL response body.
	Responses map[string]json.RawMessage
	// Errors holds one entry per spoke that produced any non-OK outcome
	// (offline, timeout, http_error). Skipped spokes are NOT in this map —
	// they appear in Skipped instead. Keyed by node_id.
	Errors map[string]error
	// Skipped holds one entry per spoke filtered out before fan-out, keyed by
	// node_id, with the SkipReason as the value.
	Skipped map[string]SkipReason
	// StatusUpdates lists the (node_id → new status) changes the hub should
	// apply to its registry as a side effect of this fan-out. Currently only
	// transport-level failures (StatusOffline) are emitted here; heartbeat-
	// driven status (stale) is left to the registry's own time-based reconcile.
	StatusUpdates map[string]SpokeStatus
	// Nodes is the per-node detail (every spoke considered, including skipped).
	// Order matches the input registry order for deterministic test output.
	Nodes []NodeResult
}

// FanOutClient executes fan-out GraphQL queries across a federation registry.
type FanOutClient struct {
	// HTTPClient is used for spoke /graphql calls. Nil → a default client that
	// accepts self-signed TLS certs (matches the spoke server's auto-cert).
	HTTPClient *http.Client
	// MaxConcurrency caps concurrent in-flight requests. ≤0 → default.
	MaxConcurrency int
	// PerNodeTimeout is the per-spoke deadline. ≤0 → default.
	PerNodeTimeout time.Duration
	// HubDDxVersion / HubSchemaVersion drive the version handshake gate.
	// Empty → version filter is skipped (test convenience).
	HubDDxVersion    string
	HubSchemaVersion string
	// Logger receives info/warn lines; nil → log.Printf.
	Logger func(format string, args ...any)
	// Now is the time source used for Duration measurement. Nil → time.Now.
	Now func() time.Time
}

// NewFanOutClient builds a FanOutClient with defaults filled in.
func NewFanOutClient() *FanOutClient {
	return &FanOutClient{
		HTTPClient: &http.Client{
			// Per-request deadlines drive cancellation; this is just a safety
			// net for misbehaving servers that never close the connection.
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		},
		MaxConcurrency: DefaultFanOutMaxConcurrency,
		PerNodeTimeout: DefaultFanOutPerNodeTimeout,
	}
}

func (c *FanOutClient) logf(format string, args ...any) {
	if c.Logger != nil {
		c.Logger(format, args...)
		return
	}
	log.Printf(format, args...)
}

func (c *FanOutClient) now() time.Time {
	if c.Now != nil {
		return c.Now()
	}
	return time.Now()
}

func (c *FanOutClient) maxConcurrency() int {
	if c.MaxConcurrency <= 0 {
		return DefaultFanOutMaxConcurrency
	}
	return c.MaxConcurrency
}

func (c *FanOutClient) perNodeTimeout() time.Duration {
	if c.PerNodeTimeout <= 0 {
		return DefaultFanOutPerNodeTimeout
	}
	return c.PerNodeTimeout
}

func (c *FanOutClient) httpClient() *http.Client {
	if c.HTTPClient != nil {
		return c.HTTPClient
	}
	return http.DefaultClient
}

// Execute fans out req across spokes. Returns a merged FanOutResult; never
// returns a non-nil error for per-spoke failures — those are surfaced through
// FanOutResult.Errors. A non-nil error is reserved for misuse (e.g. nil req).
//
// The set of spokes considered is the input slice. Callers typically pass the
// hub registry's spokes filtered by Status == active|stale (offline/degraded
// handling depends on policy and is left to the caller). Skipped spokes still
// appear in the per-node Nodes detail with OutcomeSkipped + SkipReason.
//
// Cancellation: if ctx is canceled, in-flight goroutines abort their HTTP
// calls and return OutcomeOffline (with ctx.Err() as cause); callers that want
// to distinguish caller-cancellation from spoke failure should check ctx.Err()
// after Execute returns.
func (c *FanOutClient) Execute(ctx context.Context, spokes []SpokeRecord, req *FanOutRequest) (*FanOutResult, error) {
	if req == nil {
		return nil, errors.New("federation: fanout request is nil")
	}
	if strings.TrimSpace(req.Query) == "" {
		return nil, errors.New("federation: fanout request query is empty")
	}

	body, err := json.Marshal(struct {
		Query         string         `json:"query"`
		OperationName string         `json:"operationName,omitempty"`
		Variables     map[string]any `json:"variables,omitempty"`
	}{req.Query, req.OperationName, req.Variables})
	if err != nil {
		return nil, fmt.Errorf("federation: marshal fanout query: %w", err)
	}

	results := make([]NodeResult, len(spokes))
	sem := make(chan struct{}, c.maxConcurrency())
	var wg sync.WaitGroup

	for i := range spokes {
		i := i
		s := spokes[i]
		// Pre-flight filters: version, capability, URL.
		if skip, reason, detail := c.preflightSkip(s, req.RequiredCapabilities); skip {
			c.logf("federation fanout: skip node_id=%q reason=%s detail=%q", s.NodeID, reason, detail)
			results[i] = NodeResult{
				NodeID:     s.NodeID,
				URL:        s.URL,
				Outcome:    OutcomeSkipped,
				SkipReason: reason,
				SkipDetail: detail,
			}
			continue
		}

		wg.Add(1)
		go func() {
			defer wg.Done()
			select {
			case sem <- struct{}{}:
			case <-ctx.Done():
				results[i] = NodeResult{
					NodeID:  s.NodeID,
					URL:     s.URL,
					Outcome: OutcomeOffline,
					Status:  StatusOffline,
					Err:     ctx.Err(),
				}
				return
			}
			defer func() { <-sem }()

	var runsData struct {
		FederatedRuns []struct {
			NodeID          string `json:"nodeId"`
			ProjectURL      string `json:"projectUrl"`
			WriteCapability bool   `json:"writeCapability"`
			Status          string `json:"status"`
			Run             struct {
				ID     string `json:"id"`
				Layer  string `json:"layer"`
				Status string `json:"status"`
			} `json:"run"`
		} `json:"federatedRuns"`
	}
	if err := json.Unmarshal(respRuns["data"], &runsData); err != nil {
		t.Fatalf("unmarshal runs: %v", err)
	}
	if len(runsData.FederatedRuns) != 2 {
		t.Fatalf("want 2 federated runs, got %d", len(runsData.FederatedRuns))
	}
	for _, fr := range runsData.FederatedRuns {
		if fr.Run.ID == "" || fr.Run.Layer == "" {
			t.Errorf("row %s: malformed run payload %+v", fr.NodeID, fr.Run)
		}
	}

	// federatedProjects: one row per spoke; projectId == project.id.
	respProjects := gqlPost(t, h, `{ federatedProjects {
		nodeId projectId projectUrl writeCapability status project { id name path }
	} }`)
	var projectsData struct {
		FederatedProjects []struct {
			NodeID     string `json:"nodeId"`
			ProjectID  string `json:"projectId"`
			ProjectURL string `json:"projectUrl"`
			Project    struct {
				ID   string `json:"id"`
				Name string `json:"name"`
				Path string `json:"path"`
			} `json:"project"`
		} `json:"federatedProjects"`
	}
	if err := json.Unmarshal(respProjects["data"], &projectsData); err != nil {
		t.Fatalf("unmarshal projects: %v", err)
	}
	if len(projectsData.FederatedProjects) != 2 {
		t.Fatalf("want 2 federated projects, got %d", len(projectsData.FederatedProjects))
	}
	for _, fp := range projectsData.FederatedProjects {
		if fp.ProjectID != fp.Project.ID {
			t.Errorf("row %s: routing projectId %q != project.id %q",
				fp.NodeID, fp.ProjectID, fp.Project.ID)
		}
	}
}

