					{"node": map[string]any{
						"id": "ddx-V1", "title": "compat bead", "status": "open",
						"priority": 0, "issueType": "task",
						"createdAt": "2026-05-01T00:00:00Z", "updatedAt": "2026-05-01T00:00:00Z",
					}},
				}},
			},
		}
	})

	skewed := newSpokeServer(t, func(req map[string]any) any {
		t.Errorf("skewed spoke should not be contacted by fan-out")
		return map[string]any{"data": map[string]any{}}
	})

	fed := &stubFederation{
		client: federation.NewFanOutClient(),
		spokes: []federation.SpokeRecord{
			{
				NodeID: "node-compat", Name: "compat", URL: compatible.URL,
				DDxVersion: "0.1.0", SchemaVersion: federation.CurrentSchemaVersion,
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusActive,
			},
			{
				NodeID: "node-skew", Name: "skew", URL: skewed.URL,
				// Major-version skew → handshake rejects.
				DDxVersion: "9.0.0", SchemaVersion: federation.CurrentSchemaVersion,
				RegisteredAt: now, LastHeartbeat: now, Status: federation.StatusDegraded,
			},
		},
	}
	fed.client.HubDDxVersion = "0.1.0"
	fed.client.HubSchemaVersion = federation.CurrentSchemaVersion
	fed.client.PerNodeTimeout = 500 * time.Millisecond

	h := newGQLHandlerWithFederation(t, fed)

	respNodes := gqlPost(t, h, `{ federationNodes { nodeId status ddxVersion } }`)
	var nodesData struct {
		FederationNodes []struct {
			NodeID     string `json:"nodeId"`
			Status     string `json:"status"`
			DdxVersion string `json:"ddxVersion"`
		} `json:"federationNodes"`
	}
	if err := json.Unmarshal(respNodes["data"], &nodesData); err != nil {
		t.Fatalf("unmarshal nodes: %v", err)
	}
	if len(nodesData.FederationNodes) != 2 {
		t.Fatalf("federationNodes: want 2 rows (skewed spoke must still be visible), got %d", len(nodesData.FederationNodes))
	}
	foundSkew := false
	for _, n := range nodesData.FederationNodes {
		if n.NodeID == "node-skew" {
			foundSkew = true
			if n.Status != "degraded" {
				t.Errorf("skewed spoke status: want degraded, got %q", n.Status)
			}
			if n.DdxVersion != "9.0.0" {
				t.Errorf("skewed spoke ddxVersion not rendered through federationNodes")
			}
		}
	}
	if !foundSkew {
		t.Error("skewed spoke missing from federationNodes")
	}

	respBeads := gqlPost(t, h, `{ federatedBeads { nodeId } }`)
	var beadsData struct {
		FederatedBeads []struct {
			NodeID string `json:"nodeId"`
		} `json:"federatedBeads"`
	}
	if err := json.Unmarshal(respBeads["data"], &beadsData); err != nil {
		t.Fatalf("unmarshal beads: %v", err)
	}
	if len(beadsData.FederatedBeads) != 1 {
		t.Fatalf("federatedBeads: want 1 row from compatible spoke only, got %d", len(beadsData.FederatedBeads))
	}
	if beadsData.FederatedBeads[0].NodeID != "node-compat" {
		t.Errorf("federatedBeads row: want node-compat, got %q", beadsData.FederatedBeads[0].NodeID)
	}
}

			defer func() { <-sem }()
			results[i] = c.callOne(ctx, s, body)
		}()
	}
	wg.Wait()

	out := &FanOutResult{
		Responses:     map[string]json.RawMessage{},
		Errors:        map[string]error{},
		Skipped:       map[string]SkipReason{},
		StatusUpdates: map[string]SpokeStatus{},
		Nodes:         results,
	}
	for _, r := range results {
		switch r.Outcome {
		case OutcomeOK:
			out.Responses[r.NodeID] = r.Response
		case OutcomeSkipped:
			out.Skipped[r.NodeID] = r.SkipReason
		default:
			if r.Err != nil {
				out.Errors[r.NodeID] = r.Err
			} else {
				out.Errors[r.NodeID] = fmt.Errorf("fanout: %s", r.Outcome)
			}
		}
		if r.Status != "" {
			out.StatusUpdates[r.NodeID] = r.Status
		}
	}
	return out, nil
}

// preflightSkip returns (true, reason, detail) when the spoke must be skipped
// before any HTTP call is issued.
func (c *FanOutClient) preflightSkip(s SpokeRecord, requiredCaps []string) (bool, SkipReason, string) {
	if c.HubDDxVersion != "" && c.HubSchemaVersion != "" {
		hs := Handshake(c.HubDDxVersion, c.HubSchemaVersion, s.DDxVersion, s.SchemaVersion)
		if !hs.Accept {
			return true, SkipReasonIncompatibleVersion, hs.Reason
		}
	}
	if len(requiredCaps) > 0 {
		have := map[string]struct{}{}
		for _, c := range s.Capabilities {
			// Skip the synthetic identity-fingerprint capability.
			if strings.HasPrefix(c, "@identity:") {
				continue
			}
			have[c] = struct{}{}
		}
		for _, want := range requiredCaps {
			if _, ok := have[want]; !ok {
				return true, SkipReasonMissingCapability, want
			}
		}
	}
	if strings.TrimSpace(s.URL) == "" {
		return true, SkipReasonInvalidURL, "empty url"
	}
	if _, err := url.Parse(s.URL); err != nil {
		return true, SkipReasonInvalidURL, err.Error()
	}
	return false, "", ""
}

// callOne issues the GraphQL POST against one spoke under per-node timeout.
func (c *FanOutClient) callOne(ctx context.Context, s SpokeRecord, body []byte) NodeResult {
	start := c.now()
	cctx, cancel := context.WithTimeout(ctx, c.perNodeTimeout())
	defer cancel()

	endpoint := strings.TrimRight(s.URL, "/") + "/graphql"
	req, err := http.NewRequestWithContext(cctx, http.MethodPost, endpoint, bytes.NewReader(body))
	if err != nil {
		return NodeResult{
			NodeID:   s.NodeID,
			URL:      s.URL,
			Outcome:  OutcomeOffline,
			Status:   StatusOffline,
			Err:      err,
			Duration: c.now().Sub(start),
		}
	}
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("Accept", "application/json")

	resp, err := c.httpClient().Do(req)
	if err != nil {
		// Distinguish per-node timeout (deadline exceeded on cctx but parent
		// ctx still live) from caller cancellation and from generic transport
		// failure. Per-node timeout → keep last-known status; transport
		// failure → flip to offline.
		if cctx.Err() == context.DeadlineExceeded && ctx.Err() == nil {
			return NodeResult{
				NodeID:   s.NodeID,
				URL:      s.URL,
				Outcome:  OutcomeTimeout,
				Err:      fmt.Errorf("per-node timeout after %s: %w", c.perNodeTimeout(), err),
				Duration: c.now().Sub(start),
			}
		}
		return NodeResult{
			NodeID:   s.NodeID,
			URL:      s.URL,
			Outcome:  OutcomeOffline,
			Status:   StatusOffline,
			Err:      err,
			Duration: c.now().Sub(start),
		}
	}
	defer func() { _ = resp.Body.Close() }()

	buf, readErr := io.ReadAll(resp.Body)
	if readErr != nil {
		// Mid-response disconnect — transport-level failure → offline.
		return NodeResult{
			NodeID:     s.NodeID,
			URL:        s.URL,
			Outcome:    OutcomeOffline,
			Status:     StatusOffline,
			HTTPStatus: resp.StatusCode,
			Err:        fmt.Errorf("read body: %w", readErr),
			Duration:   c.now().Sub(start),
		}
	}

	if resp.StatusCode < 200 || resp.StatusCode >= 300 {
		snippet := string(buf)
		if len(snippet) > 256 {
			snippet = snippet[:256] + "…"
		}
		return NodeResult{
			NodeID:     s.NodeID,
			URL:        s.URL,
			Outcome:    OutcomeHTTPError,
			HTTPStatus: resp.StatusCode,
			Err:        fmt.Errorf("spoke returned HTTP %d: %s", resp.StatusCode, snippet),
			Duration:   c.now().Sub(start),
		}
	}

	return NodeResult{
		NodeID:     s.NodeID,
		URL:        s.URL,
		Outcome:    OutcomeOK,
		HTTPStatus: resp.StatusCode,
		Response:   json.RawMessage(buf),
		Duration:   c.now().Sub(start),
	}
}

// ForwardMutation POSTs an arbitrary mutation envelope to the target spoke's
// /graphql endpoint and preserves the supplied headers verbatim.
func (c *FanOutClient) ForwardMutation(ctx context.Context, target *SpokeRecord, body []byte, headers map[string]string) (*http.Response, error) {
	if target == nil {
		return nil, fmt.Errorf("federation: target spoke is nil")
	}
	endpoint := strings.TrimRight(target.URL, "/") + "/graphql"
	req, err := http.NewRequestWithContext(ctx, http.MethodPost, endpoint, bytes.NewReader(body))
	if err != nil {
		return nil, err
	}
	for k, v := range headers {
		req.Header.Set(k, v)
	}
	return c.httpClient().Do(req)
}

// Package federation defines the hub-side federation registry: state types,
// persistence, and reconciliation helpers. No HTTP layer here — that lands in
// later beads. The on-disk format carries a schema_version field for forward
// compatibility (see ADR-007 and FEAT-026).
package federation

import (
	"fmt"
	"strings"
	"time"
)

// CurrentSchemaVersion is the schema_version this build writes. Reading code
// must accept older versions and migrate; writing code always emits this.
const CurrentSchemaVersion = "1"

// SpokeStatus is the lifecycle/health status of a registered spoke.
//
// The states are:
//   - StatusRegistered: spoke has registered but no heartbeat has been observed yet.
//   - StatusActive:     last heartbeat is recent (the live/healthy state).
//   - StatusStale:      no heartbeat for ≥ 2 minutes.
//   - StatusOffline:    fan-out to the spoke failed (connection refused, unreachable).
//   - StatusDegraded:   version handshake accepted with minor/schema drift.
//
// The bead-level enum collapses ADR-007's split between compat_status and
// liveness into a single field for v1 persistence; richer surface fields can
// be added in later schema versions without breaking older readers.
type SpokeStatus string

const (
	StatusRegistered SpokeStatus = "registered"
	StatusActive     SpokeStatus = "active"
	StatusStale      SpokeStatus = "stale"
	StatusOffline    SpokeStatus = "offline"
	StatusDegraded   SpokeStatus = "degraded"
)

// Valid reports whether s is one of the known status values.
func (s SpokeStatus) Valid() bool {
	switch s {
	case StatusRegistered, StatusActive, StatusStale, StatusOffline, StatusDegraded:
		return true
	}
	return false
}

// SpokeRecord is one entry in the federation registry.
type SpokeRecord struct {
	NodeID        string      `json:"node_id"`
	Name          string      `json:"name"`
	URL           string      `json:"url"`
	DDxVersion    string      `json:"ddx_version,omitempty"`
	SchemaVersion string      `json:"schema_version,omitempty"`
	Capabilities  []string    `json:"capabilities,omitempty"`
	ProjectIDs    []string    `json:"project_ids,omitempty"`
	RegisteredAt  time.Time   `json:"registered_at"`
	LastHeartbeat time.Time   `json:"last_heartbeat"`
	Status        SpokeStatus `json:"status"`
}

// FederationRegistry is the persisted hub state.
type FederationRegistry struct {
	SchemaVersion string        `json:"schema_version"`
	Spokes        []SpokeRecord `json:"spokes"`
}

// NewRegistry returns an empty registry stamped with the current schema version.
func NewRegistry() *FederationRegistry {
	return &FederationRegistry{
		SchemaVersion: CurrentSchemaVersion,
		Spokes:        []SpokeRecord{},
	}
}

// FindSpoke returns the record for nodeID, or nil if absent.
func (r *FederationRegistry) FindSpoke(nodeID string) *SpokeRecord {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			return &r.Spokes[i]
		}
	}
	return nil
}

// UpsertSpoke inserts or replaces a spoke by NodeID. NodeID must be non-empty.
func (r *FederationRegistry) UpsertSpoke(rec SpokeRecord) error {
	if rec.NodeID == "" {
		return fmt.Errorf("federation: spoke node_id is required")
	}
	if rec.Status == "" {
		rec.Status = StatusRegistered
	}
	if !rec.Status.Valid() {
		return fmt.Errorf("federation: invalid spoke status %q", rec.Status)
	}
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == rec.NodeID {
			r.Spokes[i] = rec
			return nil
		}
	}
	r.Spokes = append(r.Spokes, rec)
	return nil
}

// RemoveSpoke removes a spoke by NodeID; reports whether it was present.
func (r *FederationRegistry) RemoveSpoke(nodeID string) bool {
	for i := range r.Spokes {
		if r.Spokes[i].NodeID == nodeID {
			r.Spokes = append(r.Spokes[:i], r.Spokes[i+1:]...)
			return true
		}
	}
	return false
}

// SetStatus updates the status of a spoke and returns true on success. Refuses
// unknown status values so callers cannot silently corrupt persisted state.
func (r *FederationRegistry) SetStatus(nodeID string, status SpokeStatus) error {
	if !status.Valid() {
		return fmt.Errorf("federation: invalid status %q", status)
	}
	rec := r.FindSpoke(nodeID)
	if rec == nil {
		return fmt.Errorf("federation: spoke %q not found", nodeID)
	}
	rec.Status = status
	return nil
}

// ReconcileLiveness derives status purely from elapsed time since the last
// heartbeat for spokes whose status is currently in {registered, active,
// stale}. Statuses set externally (offline from fan-out failure, degraded from
// version handshake) are left alone — those are not time-driven.
//
//   - now - last_heartbeat <  staleAfter            → active
//   - now - last_heartbeat >= staleAfter            → stale
//
// A zero LastHeartbeat keeps a freshly-registered spoke in StatusRegistered
// until the first heartbeat is observed.
func (r *FederationRegistry) ReconcileLiveness(now time.Time, staleAfter time.Duration) {
	for i := range r.Spokes {
		s := &r.Spokes[i]
		switch s.Status {
		case StatusOffline, StatusDegraded:
			continue
		}
		if s.LastHeartbeat.IsZero() {
			s.Status = StatusRegistered
			continue
		}
		if now.Sub(s.LastHeartbeat) >= staleAfter {
			s.Status = StatusStale
		} else {
			s.Status = StatusActive
		}
	}
}

// RouteMutationToProjectOwner returns the spoke registered as owning projectID.
// A project may be owned by exactly one spoke. If no owner is registered, or if
// multiple spokes claim the same project, the helper returns an error.
func RouteMutationToProjectOwner(registry *FederationRegistry, projectID string) (*SpokeRecord, error) {
	if registry == nil {
		return nil, fmt.Errorf("federation: registry is nil")
	}
	projectID = strings.TrimSpace(projectID)
	if projectID == "" {
		return nil, fmt.Errorf("federation: project_id required")
	}

	var match *SpokeRecord
	for i := range registry.Spokes {
		spoke := &registry.Spokes[i]
		for _, owned := range spoke.ProjectIDs {
			if owned == projectID {
				if match != nil {
					return nil, fmt.Errorf("federation: project %q has multiple registered owners", projectID)
				}
				copy := *spoke
				match = &copy
				break
			}
		}
	}
	if match == nil {
		return nil, fmt.Errorf("federation: no registered spoke owns project %q", projectID)
	}
	return match, nil
}

	if _, err := c.Execute(context.Background(), nil, nil); err == nil {
		t.Fatalf("expected error on nil request")
	}
	if _, err := c.Execute(context.Background(), nil, &FanOutRequest{Query: "  "}); err == nil {
		t.Fatalf("expected error on empty query")
	}
}

func TestFanOut_PostsGraphQLPayload(t *testing.T) {
	var got struct {
		Query         string         `json:"query"`
		OperationName string         `json:"operationName"`
		Variables     map[string]any `json:"variables"`
	}
	_, s := newSpokeServer(t, func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			t.Errorf("method = %s, want POST", r.Method)
		}
		if ct := r.Header.Get("Content-Type"); ct != "application/json" {
			t.Errorf("Content-Type = %q, want application/json", ct)
		}
		if err := json.NewDecoder(r.Body).Decode(&got); err != nil {
			t.Errorf("decode body: %v", err)
		}
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": "ok"}))
	})

	c := NewFanOutClient()
	c.HubDDxVersion = "0.1.0"
	c.HubSchemaVersion = CurrentSchemaVersion
	_, err := c.Execute(context.Background(), []SpokeRecord{s}, &FanOutRequest{
		Query:         "query Q { x }",
		OperationName: "Q",
		Variables:     map[string]any{"foo": "bar"},
	})
	if err != nil {
		t.Fatalf("execute: %v", err)
	}
	if got.Query != "query Q { x }" || got.OperationName != "Q" || got.Variables["foo"] != "bar" {
		t.Fatalf("posted payload mismatch: %+v", got)
	}
}

func TestForwardMutation_HeadersReachSpoke(t *testing.T) {
	var gotMethod string
	var gotPath string
	var gotBody []byte
	var gotHeaders http.Header

	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		gotMethod = r.Method
		gotPath = r.URL.Path
		gotHeaders = r.Header.Clone()
		gotBody, _ = io.ReadAll(r.Body)
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusCreated)
		_, _ = w.Write(okGraphQLBody(t, map[string]any{"data": map[string]any{"ok": true}}))
	}))
	t.Cleanup(srv.Close)

	c := NewFanOutClient()
	headers := map[string]string{
		"X-DDx-Origin-Identity":      "origin-123",
		"X-DDx-Coordinator-Identity": "coord-456",
		"X-Trace-Token":              "trace-789",
	}
	resp, err := c.ForwardMutation(context.Background(), &SpokeRecord{NodeID: "node-1", URL: srv.URL}, []byte(`{"query":"mutation { __typename }"}`), headers)
	if err != nil {
		t.Fatalf("forward mutation: %v", err)
	}
	defer func() { _ = resp.Body.Close() }()

	if gotMethod != http.MethodPost {
		t.Fatalf("method = %s, want POST", gotMethod)
	}
	if gotPath != "/graphql" {
		t.Fatalf("path = %s, want /graphql", gotPath)
	}
	for k, v := range headers {
		if got := gotHeaders.Get(k); got != v {
			t.Fatalf("header %s = %q, want %q", k, got, v)
		}
	}
	if string(gotBody) != `{"query":"mutation { __typename }"}` {
		t.Fatalf("body = %s", string(gotBody))
	}
	if resp.StatusCode != http.StatusCreated {
		t.Fatalf("status = %d, want %d", resp.StatusCode, http.StatusCreated)
	}
}

package graphql

import (
	"context"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// RunRequeueEventKind is the BeadEvent.Kind appended to the originating bead's
// audit log every time runRequeue successfully re-queues that bead. The body
// captures operator identity, the run id under attempt, the optional layer
// override, and the idempotency key so duplicate-key collapses are traceable.
const RunRequeueEventKind = "run_requeue"

// RunRequeue implements the runRequeue mutation: given a runId, look up the
// originating bead, atomically dedupe by idempotencyKey, reopen the bead so
// the work can claim it again, and append an audit event capturing
// operator identity. Concurrent calls with the same idempotencyKey collapse
// to a single re-queue (the second caller receives deduplicated=true and the
// same bead).
func (r *mutationResolver) RunRequeue(ctx context.Context, input RunRequeueInput) (*RunRequeueResult, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if strings.TrimSpace(input.RunID) == "" {
		return nil, fmt.Errorf("runRequeue: runId is required")
	}
	if strings.TrimSpace(input.IdempotencyKey) == "" {
		return nil, fmt.Errorf("runRequeue: idempotencyKey is required")
	}

	cache := r.RunRequeueIdempotency
	if cache == nil {
		return nil, fmt.Errorf("runRequeue: idempotency cache not configured")
	}

	provider, ok := r.State.(RunsStateProvider)
	if !ok {
		return nil, fmt.Errorf("runRequeue: runs state provider not configured")
	}
	run, ok := provider.GetRunGraphQL(input.RunID)
	if !ok || run == nil {
		return nil, fmt.Errorf("runRequeue: run %s not found", input.RunID)
	}
	if run.BeadID == nil || *run.BeadID == "" {
		return nil, fmt.Errorf("runRequeue: run %s has no originating bead", input.RunID)
	}
	originatingBeadID := *run.BeadID

	store := r.beadStore(ctx)

	// Atomic claim block: serialize lookup+reserve+store so concurrent calls
	// with the same idempotencyKey collapse to a single re-queue. The store's
	// per-bead Update is itself atomic; this mutex covers the cache plus the
	// audit event so duplicate keys never produce two reopen+event pairs.
	r.runRequeueMu.Lock()
	defer r.runRequeueMu.Unlock()

	if cachedID, hit := cache.Lookup(input.IdempotencyKey); hit {
		// A prior call under this key already requeued a bead. Return that
		// bead unchanged regardless of its current lifecycle status —
		// "duplicate-key returns existing requeued bead, not error".
		if existing, err := store.Get(ctx, cachedID); err == nil {
			return &RunRequeueResult{
				Bead:         beadModelFromBead(existing),
				Deduplicated: true,
			}, nil
		}
		// The cached id points at a missing bead — fall through and replay
		// the requeue against the run's current originating bead.
	}

	if err := store.Reopen(originatingBeadID, "run requeued", ""); err != nil {
		return nil, fmt.Errorf("runRequeue: reopen bead %s: %w", originatingBeadID, err)
	}

	identity := operatorPromptIdentityInfo{kind: "unknown", actor: "anonymous"}
	if httpReq := httpRequestFromContext(ctx); httpReq != nil {
		identity = operatorPromptIdentity(httpReq)
	}
	layerOverride := ""
	if input.Layer != nil {
		layerOverride = *input.Layer
	}
	auditBody := fmt.Sprintf(
		"identity=%s actor=%s run_id=%s idempotency_key=%s layer_override=%s",
		identity.kind,
		identity.actor,
		input.RunID,
		input.IdempotencyKey,
		layerOverride,
	)
	if err := store.AppendEvent(originatingBeadID, bead.BeadEvent{
		Kind:    RunRequeueEventKind,
		Summary: "run requeued",
		Body:    auditBody,
		Actor:   identity.actor,
		Source:  "graphql:runRequeue",
	}); err != nil {
		return nil, fmt.Errorf("runRequeue: append audit event: %w", err)
	}

	cache.Store(input.IdempotencyKey, originatingBeadID)

	persisted, err := store.Get(ctx, originatingBeadID)
	if err != nil {
		return nil, err
	}
	return &RunRequeueResult{
		Bead:         beadModelFromBead(persisted),
		Deduplicated: false,
	}, nil
}

package graphql

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"encoding/hex"
	"errors"
	"fmt"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/vektah/gqlparser/v2/gqlerror"
)

// DefaultOperatorPromptCapBytes is the fallback prompt-body cap when the
// resolver was constructed without an explicit PromptCapBytes value. It
// mirrors the inline-prompt cap enforced by the REST /api/agent/run handler
// (evidence.DefaultMaxPromptBytes) so the two write surfaces share a limit.
const DefaultOperatorPromptCapBytes = evidence.DefaultMaxPromptBytes

// CSRFHeaderName is the HTTP header that must carry the server-issued CSRF
// token on operatorPromptSubmit calls (FEAT operator-prompts, Story 15).
const CSRFHeaderName = "X-CSRF-Token"

// OperatorPromptIdempotencyTTL is the window during which duplicate
// idempotency keys deduplicate to the original bead.
const OperatorPromptIdempotencyTTL = 24 * time.Hour

// OperatorPromptEventKind is the BeadEvent.Kind appended to every
// operator-prompt bead's audit log on submit, capturing the originating
// identity (localhost OR ts-net WhoIs).
const OperatorPromptEventKind = "operator_prompt_submit"

// OperatorPromptApproveEventKind is the BeadEvent.Kind appended to an
// operator-prompt bead's audit log when it transitions proposed → open
// (either via operatorPromptApprove or via the auto-approve path on
// operatorPromptSubmit).
const OperatorPromptApproveEventKind = "operator_prompt_approve"

// OperatorPromptCancelEventKind is the BeadEvent.Kind appended to an
// operator-prompt bead's audit log when it transitions proposed → cancelled
// via operatorPromptCancel.
const OperatorPromptCancelEventKind = "operator_prompt_cancel"

// OperatorPromptAllowlistLocalhostSentinel is the sentinel allowlist entry
// that grants any localhost-kind identity auto-approve / approve rights.
// Per the locked Story 15 decision, ts-net identities are never eligible
// regardless of the allowlist contents.
const OperatorPromptAllowlistLocalhostSentinel = "localhost"

// httpRequestKey is the context key used by the server to plumb the
// originating *http.Request into GraphQL resolver calls so the resolver can
// validate CSRF tokens and capture the originating identity.
type httpRequestKey struct{}

// WithHTTPRequest returns ctx with r attached for downstream resolver access.
// The server's GraphQL HTTP handler must call this before delegating to the
// gqlgen handler so resolvers that depend on request headers (CSRF token,
// X-Tailscale-User) work correctly.
func WithHTTPRequest(ctx context.Context, r *http.Request) context.Context {
	return context.WithValue(ctx, httpRequestKey{}, r)
}

// httpRequestFromContext retrieves the *http.Request previously attached via
// WithHTTPRequest, or nil if none was set.
func httpRequestFromContext(ctx context.Context) *http.Request {
	if v, ok := ctx.Value(httpRequestKey{}).(*http.Request); ok {
		return v
	}
	return nil
}

// CSRFTokenStore validates a CSRF token presented on a write request. The
// production implementation stores a per-process token issued at server
// startup and rotated via an explicit endpoint; tests inject a stub.
type CSRFTokenStore interface {
	Validate(token string) bool
}

// IdempotencyCache deduplicates operatorPromptSubmit calls by key within
// OperatorPromptIdempotencyTTL. Lookup returns the original bead ID stored
// under key (and true) when the key was previously seen and has not expired,
// or "", false otherwise. Store records key -> beadID at submit time.
type IdempotencyCache interface {
	Lookup(key string) (string, bool)
	Store(key, beadID string)
}

// MemoryIdempotencyCache is a process-local in-memory IdempotencyCache with
// TTL-based eviction. It is safe for concurrent use.
type MemoryIdempotencyCache struct {
	mu  sync.Mutex
	now func() time.Time
	ttl time.Duration
	m   map[string]idempotencyEntry
}

type idempotencyEntry struct {
	beadID    string
	expiresAt time.Time
}

// NewMemoryIdempotencyCache constructs a cache with the operator-prompt
// default 24h TTL and the real wall clock.
func NewMemoryIdempotencyCache() *MemoryIdempotencyCache {
	return &MemoryIdempotencyCache{
		now: time.Now,
		ttl: OperatorPromptIdempotencyTTL,
		m:   make(map[string]idempotencyEntry),
	}
}

// Lookup returns the bead ID associated with key when present and unexpired.
func (c *MemoryIdempotencyCache) Lookup(key string) (string, bool) {
	if key == "" {
		return "", false
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	e, ok := c.m[key]
	if !ok {
		return "", false
	}
	if c.now().After(e.expiresAt) {
		delete(c.m, key)
		return "", false
	}
	return e.beadID, true
}

// Store records key -> beadID with the configured TTL window.
func (c *MemoryIdempotencyCache) Store(key, beadID string) {
	if key == "" {
		return
	}
	c.mu.Lock()
	defer c.mu.Unlock()
	c.m[key] = idempotencyEntry{beadID: beadID, expiresAt: c.now().Add(c.ttl)}
}

// StaticCSRFTokenStore is a single-secret CSRFTokenStore — the token is
// generated once at server startup and validated by constant-time compare.
type StaticCSRFTokenStore struct {
	token string
}

// NewStaticCSRFTokenStore returns a store seeded with a freshly-generated
// 32-byte random token.
func NewStaticCSRFTokenStore() (*StaticCSRFTokenStore, error) {
	var buf [32]byte
	if _, err := rand.Read(buf[:]); err != nil {
		return nil, fmt.Errorf("csrf: generate token: %w", err)
	}
	return &StaticCSRFTokenStore{token: hex.EncodeToString(buf[:])}, nil
}

// NewStaticCSRFTokenStoreWithToken constructs a store using the supplied
// token (used by tests so a deterministic header value can be sent).
func NewStaticCSRFTokenStoreWithToken(token string) *StaticCSRFTokenStore {
	return &StaticCSRFTokenStore{token: token}
}

// Token returns the stored CSRF token (used by the server to expose it via a
// dedicated endpoint or embed it in served HTML).
func (s *StaticCSRFTokenStore) Token() string { return s.token }

// Validate compares presented to the stored token using a length-equal
// constant-time check.
func (s *StaticCSRFTokenStore) Validate(presented string) bool {
	if presented == "" || len(presented) != len(s.token) {
		return false
	}
	var diff byte
	for i := 0; i < len(s.token); i++ {
		diff |= s.token[i] ^ presented[i]
	}
	return diff == 0
}

// errCSRF is returned by OperatorPromptSubmit when the CSRF check fails.
// The HTTP transport for the GraphQL endpoint surfaces this as a 403; the
// resolver itself only emits the error.
var errCSRF = errors.New("operator-prompts: CSRF token missing or invalid (status: 403)")

// errCrossOrigin is returned by OperatorPromptSubmit when the request carries
// an Origin header whose host portion does not match the request Host. This
// blocks browser cross-origin POSTs even from a trusted-loopback peer (CSRF
// defense in depth alongside the per-session token).
var errCrossOrigin = errors.New("operator-prompts: cross-origin request rejected (status: 403)")

// promptCapError builds the structured cap-error envelope returned by
// operatorPromptSubmit when the prompt body exceeds the configured cap. The
// envelope is surfaced inside `errors[].extensions` so the SvelteKit
// frontend can show observed/cap bytes without parsing the message string.
func promptCapError(observed, cap int) error {
	return &gqlerror.Error{
		Message: fmt.Sprintf(
			"operator-prompts: prompt body exceeds cap: observed %d bytes, cap %d bytes (status: 400)",
			observed, cap,
		),
		Extensions: map[string]any{
			"code":           "PROMPT_TOO_LARGE",
			"status":         400,
			"observed_bytes": observed,
			"cap_bytes":      cap,
			"config_hint":    ".ddx/config.yaml:evidence_caps.max_prompt_bytes",
		},
	}
}

// errAutoApproveDenied is returned by OperatorPromptApprove (and is the
// reason auto-approve gets demoted to a plain proposed bead inside
// OperatorPromptSubmit) when the caller's identity is not on the per-project
// allowlist. ts-net identities always hit this path regardless of allowlist
// contents (locked Story 15 decision: ts-net peers may not blanket
// auto-approve operator prompts).
var errAutoApproveDenied = errors.New("operator-prompts: identity not on per-project auto-approve allowlist (status: 403)")

// errSubmitDenied is returned by OperatorPromptSubmit when the caller is a
// ts-net peer whose identity is not on the per-project allowlist
// (web.operator_prompt.allow_identities). Localhost callers are always
// allowed to submit because they have already cleared the requireTrusted
// loopback gate; ts-net peers carry only network-layer trust, so the
// per-project allowlist is the authorization step. Empty allowlist →
// every ts-net peer is rejected (the locked Story 15 default that yields a
// "ts-net peers see read-only UI" outcome).
var errSubmitDenied = errors.New("operator-prompts: ts-net identity not on per-project allow_identities allowlist (status: 403)")

// OperatorPromptSubmit implements the operatorPromptSubmit mutation: it
// validates the CSRF token from the request header, deduplicates within a
// 24h window by idempotency key, and (on first submission) creates a new
// operator-prompt bead in the proposed status with an audit event capturing
// the originating identity (localhost user OR ts-net WhoIs).
func (r *mutationResolver) OperatorPromptSubmit(ctx context.Context, input OperatorPromptSubmitInput) (*OperatorPromptSubmitResult, error) {

	// invoke operatorPromptApprove. The locked Story 15 decision restricts
	// approval to configured-localhost identities — ts-net identities are
	// NEVER eligible regardless of the allowlist contents. The literal
	// sentinel "localhost" in the list matches any localhost actor; otherwise
	// the entry must equal the actor string produced by operatorPromptIdentity
	// (e.g. "localhost:127.0.0.1:55812"). An empty allowlist disables both
	// auto-approve and the manual approve mutation for this project.
	OperatorPromptAutoApproveAllowlist []string
	// PromptCapBytes caps the prompt body size accepted by
	// operatorPromptSubmit. When zero the resolver falls back to
	// DefaultOperatorPromptCapBytes (= evidence.DefaultMaxPromptBytes), which
	// matches the inline-prompt cap on /api/agent/run.
	PromptCapBytes int
	// BuildSHA is the server build commit recorded on the operator-prompt
	// audit event so the immutable first event captures the binary version
	// that accepted the submission. Empty -> "unknown".
	BuildSHA string
	// NodeID is the receiving server's stable node ID, captured on the
	// operator-prompt audit event. Used together with the originating
	// X-Tailscale-Node header (which identifies the *peer*'s node) so the
	// audit trail records both ends of the trust attestation.
	NodeID string
	// ExecuteLoopWaker, when non-nil, is signalled by the operator-prompt
	// approve / auto-approve resolvers immediately after a successful
	// proposed → open transition so a running work worker bound to
	// the project drops its idle-poll sleep and claims the bead in the
	// current tick. Nil → resolver simply skips the wake (the next tick
	// will pick the bead up after PollInterval).
	ExecuteLoopWaker ExecuteLoopWaker
	// Federation, when non-nil, supplies the spoke registry and fan-out
	// client used by the federationNodes / federated{Beads,Runs,Projects}
	// query resolvers. Nil → those queries return empty lists (the default
	// for non-hub servers).
	Federation FederationProvider
	// RunRequeueIdempotency deduplicates runRequeue mutation calls by
	// idempotency key. Concurrent and repeat calls with the same key return
	// the same originating bead and never enqueue a second time. Server
	// callers wire a process-wide instance (NewMemoryIdempotencyCache); when
	// nil, the resolver returns an error rather than silently failing open.
	RunRequeueIdempotency IdempotencyCache
	// runRequeueMu serializes the lookup+reserve+store steps of the
	// runRequeue mutation so that concurrent calls with the same
	// idempotencyKey collapse to a single re-queue (atomic claims).
	runRequeueMu sync.Mutex
	// ReportedWorkers, when non-nil, supplies the worker_ingest derived view
	// for the reportedWorkers query. Nil → resolver returns an empty list.
	ReportedWorkers ReportedWorkersProvider
	// ReviewSessions backs the reviewSession{Start,Respond,Cancel} mutations
	// and the reviewSessionEvents subscription. Nil → the resolver lazily
	// allocates an in-memory default on first use so review mutations work
	// end-to-end without external wiring (used by tests; the server package
	// supplies the production implementation).
	ReviewSessions ReviewSessionService
	// reviewMu serializes lazy allocation of ReviewSessions when no
	// implementation was wired at construction time.
	reviewMu sync.Mutex
}

// NewResolver returns a zero-initialized resolver root.
// Server construction wires the concrete collaborators after creating it.
func NewResolver() *Resolver { return &Resolver{} }

// ReportedWorkersProvider returns a snapshot of the worker_ingest derived
// view (ADR-022 rev 5 §Worker-server interface), already classified by
// freshness state. The server package supplies the production implementation.
type ReportedWorkersProvider interface {
	GetReportedWorkers() []*ReportedWorker
}

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

package graphql

// Federation resolvers (B14.6b). The hub fans out a small set of read-only
// queries to every active spoke via the B14.6a fan-out client, decorates
// each row with routing metadata (node_id, project_id, project_url,
// write_capability, status), and merges the per-spoke responses into a
// single result. The same provider surface also exposes owner-targeted write
// forwarding so mutation callers can route a single write to its owning
// project without changing the read fan-out behavior.

import (
	"context"
	"encoding/json"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// FederationProvider exposes the hub-side state required by the federated
// query resolvers. The Resolver is wired with a nil provider on non-hub
// servers; resolvers degrade to empty-list responses in that case.
type FederationProvider interface {
	// Spokes returns a snapshot of registered spokes. Implementations should
	// return a copy that callers may sort or filter without affecting the
	// underlying registry.
	Spokes() []federation.SpokeRecord
	// FanOut executes the supplied request against every spoke returned by
	// Spokes (the implementation may apply its own active/stale policy) and
	// returns the merged FanOutResult.
	FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error)
	// ForwardMutation routes one owner-targeted mutation to the owning spoke.
	// The request carries the origin, forwarding trail, and target identity
	// metadata needed to preserve the write contract.
	ForwardMutation(ctx context.Context, req *federation.ForwardMutationRequest) (*federation.ForwardMutationResponse, error)
}

// federationCapWrite is the capability string a spoke advertises when it
// allows writes from federated callers. Read-only fan-out is the v1 default
// so this field is always false until a spoke explicitly opts in.
const federationCapWrite = "write"

// federationIdentityPrefix mirrors the synthetic capability used by the hub
// to stash the identity fingerprint on a SpokeRecord. Filtered out of the
// FederationNode.capabilities surface so clients never see it.
const federationIdentityPrefix = "@identity:"

// FederationNodes returns one row per registered spoke decorated with the
// most recent fan-out outcome. When the server is not in hub mode (Resolver
// has no FederationProvider) the result is an empty list.
func (r *queryResolver) FederationNodes(ctx context.Context) ([]*FederationNode, error) {
	if r.Federation == nil {
		return []*FederationNode{}, nil
	}
	spokes := r.Federation.Spokes()
	out := make([]*FederationNode, 0, len(spokes))
	for _, s := range spokes {
		out = append(out, federationNodeFromSpoke(s, ""))
	}
	return out, nil
}

